#include <unistd.h>
#include <stdio.h>
#include <signal.h>
#include <sys/wait.h>
#include <string.h>

/* Strategy 2: SIGCHLD handler to reap all children */
void sigchld_handler(int sig) {
    (void)sig;
    int saved_errno = errno;
    while (waitpid(-1, NULL, WNOHANG) > 0)
        ;  /* reap all available zombies */
    errno = saved_errno;
}

/* Strategy 4: Double fork */
void run_detached(void) {
    pid_t pid = fork();
    if (pid == 0) {
        /* First child */
        pid_t pid2 = fork();
        if (pid2 == 0) {
            /* Grandchild: adopted by init when first child exits */
            sleep(2);  /* simulate work */
            printf("Grandchild done (ppid=%d, likely 1 or init)\n", getppid());
            _exit(0);
        }
        _exit(0);  /* first child exits immediately */
    }
    wait(NULL);  /* reap first child (fast) */
}

int main(void) {
    /* Install SIGCHLD handler */
    struct sigaction sa;
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = sigchld_handler;
    sa.sa_flags = SA_RESTART | SA_NOCLDSTOP;
    sigaction(SIGCHLD, &sa, NULL);

    /* Fork some children -- handler reaps them */
    for (int i = 0; i < 3; i++) {
        if (fork() == 0) {
            printf("Child %d (pid=%d) working...\n", i, getpid());
            _exit(0);
        }
    }

    sleep(1);  /* let children finish; handler reaps them */
    printf("No zombies!\n");

    /* Double-fork example */
    run_detached();
    printf("Detached grandchild is running independently\n");

    sleep(3);
    return 0;
}

