void daemonize(void) {
    /* Step 1: First fork */
    pid_t pid = fork();
    if (pid < 0) { perror("fork"); exit(1); }
    if (pid > 0) exit(0);  /* parent exits */

    /* Step 2: New session */
    if (setsid() == -1) { perror("setsid"); exit(1); }

    /* Step 3: Second fork (prevent acquiring terminal) */
    pid = fork();
    if (pid < 0) { perror("fork"); exit(1); }
    if (pid > 0) _exit(0);  /* first child exits */

    /* Step 4: Change working directory */
    chdir("/");

    /* Step 5: Clear umask */
    umask(0);

    /* Step 6: Close all open file descriptors */
    struct rlimit rl;
    getrlimit(RLIMIT_NOFILE, &rl);
    for (rlim_t i = 0; i < rl.rlim_cur; i++)
        close((int)i);

    /* Step 7: Redirect stdin/stdout/stderr to /dev/null */
    int fd0 = open("/dev/null", O_RDWR);  /* stdin = fd 0 */
    dup2(fd0, STDOUT_FILENO);              /* stdout = fd 1 */
    dup2(fd0, STDERR_FILENO);              /* stderr = fd 2 */
}

int main(void) {
    daemonize();

    /* Daemon main loop */
    for (;;) {
        /* Do daemon work here */
        sleep(30);
    }

    return 0;  /* unreachable */
}

