        if (argc == 0) continue;

        /* Builtin: cd */
        if (strcmp(argv[0], "cd") == 0) {
            if (argv[1] == NULL)
                chdir(getenv("HOME"));
            else if (chdir(argv[1]) == -1)
                perror("cd");
            continue;
        }

        /* Builtin: exit */
        if (strcmp(argv[0], "exit") == 0)
            break;

        /* External command: fork + exec */
        pid_t pid = fork();
        if (pid == -1) {
            perror("fork");
            continue;
        }

        if (pid == 0) {
            /* Child: execute command */
            execvp(argv[0], argv);
            fprintf(stderr, "mysh: %s: command not found\n", argv[0]);
            _exit(127);
        }

        /* Parent: wait for child */
        int status;
        waitpid(pid, &status, 0);
    }

    printf("\n");
    return 0;
}

