#include <unistd.h>
#include <stdio.h>
#include <sys/wait.h>

int main(void) {
    printf("Current process: pid=%d, ppid=%d\n", getpid(), getppid());

    pid_t child = fork();
    if (child == 0) {
        printf("Child: pid=%d, ppid=%d\n", getpid(), getppid());
        /* getppid() == parent's getpid() */
        _exit(0);
    }

    printf("Parent: my pid=%d, child pid=%d\n", getpid(), child);
    waitpid(child, NULL, 0);

    /* Demonstrate orphan reparenting */
    pid_t orphan = fork();
    if (orphan == 0) {
        sleep(1);  /* let parent exit */
        printf("Orphan: pid=%d, ppid=%d (should be 1 or subreaper)\n",
               getpid(), getppid());
        _exit(0);
    }
    /* Parent does not wait -- orphan gets reparented to init */

    return 0;
}

