#include <spawn.h>
#include <stdio.h>
#include <stdlib.h>
#include <sys/wait.h>
#include <unistd.h>

int main(void) {
    pid_t pid;
    int status;

    /* Simple: run "ls -la /tmp" */
    char *argv[] = {"ls", "-la", "/tmp", NULL};
    extern char **environ;

    int ret = posix_spawnp(&pid, "ls", NULL, NULL, argv, environ);
    if (ret != 0) {
        fprintf(stderr, "posix_spawnp: %s\n", strerror(ret));
        return 1;
    }
    waitpid(pid, &status, 0);
    printf("ls exited with %d\n", WEXITSTATUS(status));

    /* With file actions: redirect stdout to a file */
    posix_spawn_file_actions_t actions;
    posix_spawn_file_actions_init(&actions);
    posix_spawn_file_actions_addopen(&actions, STDOUT_FILENO,
        "output.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);

    char *argv2[] = {"echo", "hello from posix_spawn", NULL};
    ret = posix_spawnp(&pid, "echo", &actions, NULL, argv2, environ);
    posix_spawn_file_actions_destroy(&actions);

    if (ret == 0) {
        waitpid(pid, &status, 0);
        printf("echo wrote to output.txt\n");
    }

    return 0;
}

